select patients.patient_id , patient_name ,age , days as recovery_time from (select patient_id , days from (select patient_id , min(tests) as tests , min(dates) as days from (select patient_id , (t2-test_id) as tests , (td2-test_date) as dates from  (select pos.patient_id , pos.test_id , pos.test_date , all_pos_negative.test_id t2 , all_pos_negative.test_date td2 from (select patient_id , min(test_id) filter(where result='Positive') as test_id , min(test_date) filter(where result='Positive') as test_date from (select covid_tests.patient_id , test_id , test_date , result from (select patient_id from covid_tests group by patient_id having bool_or(result = 'Positive') and bool_or(result='Negative') ) as patients join covid_tests on patients.patient_id = covid_tests.patient_id ) as positives group by patient_id) as pos join 
(select covid_tests.patient_id , test_id , test_date , result from (select patient_id from covid_tests group by patient_id having bool_or(result = 'Positive') and bool_or(result='Negative'))as n join covid_tests on n.patient_id = covid_tests.patient_id) as all_pos_negative on pos.patient_id = all_pos_negative.patient_id and all_pos_negative.test_id > pos.test_id and all_pos_negative.result='Negative') as res ) as final group by patient_id ) as result ) as final_result join patients on final_result.patient_id = patients.patient_id order by recovery_time , patient_name;
